+/// Emit shift operand: @as(usize, @intCast(value)) using builder
+fn emitShiftOperand(self: *NativeCodegen, b: *ZigBuilder, operand: ZigValue) CodegenError!void {
+    try b.write("@as(usize, @intCast(");
