+/// Emit pow exponent: @as(u32, @intCast(value)) using builder
+fn emitPowExponent(self: *NativeCodegen, b: *ZigBuilder, operand: ZigValue) CodegenError!void {
+    try b.write("@as(u32, @intCast(");
     try self.emitZigValue(operand);
